#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 500

int countDistinctIslands(int** grid, int N, int M) {
    int count = 0;
    int** visited = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        visited[i] = (int*)malloc(M * sizeof(int));
        for (int j = 0; j < M; j++) {
            visited[i][j] = 0;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (grid[i][j] == 1 && !visited[i][j]) {
                count++;
                bfs(grid, visited, i, j, N, M);
            }
        }
    }
    return count;
}

void bfs(int** grid, int** visited, int x, int y, int N, int M) {
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};
    visited[x][y] = 1;
    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i];
        int ny = y + dy[i];
        if (nx >= 0 && nx < N && ny >= 0 && ny < M && grid[nx][ny] == 1 && !visited[nx][ny]) {
            bfs(grid, visited, nx, ny, N, M);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int** grid = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            grid[i] = (int*)malloc(M * sizeof(int));
            for (int j = 0; j < M; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        printf("%d\n", countDistinctIslands(grid, N, M));
    }
    return 0;
}

