import java.util.Scanner;
import java.util.HashSet;
import java.util.Set;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int[][] grid = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    grid[i][j] = scanner.nextInt();
                }
            }
            System.out.println(countDistinctIslands(grid));
        }
    }

    public static int countDistinctIslands(int[][] grid) {
        int count = 0;
        Set<String> uniqueIslands = new HashSet<>();
        for (int i = 0; i < grid.length; i++) {
            for (int j = 0; j < grid[0].length; j++) {
                if (grid[i][j] == 1) {
                    String islandShape = bfs(grid, i, j);
                    uniqueIslands.add(islandShape);
                }
            }
        }
        return uniqueIslands.size();
    }

    public static String bfs(int[][] grid, int x, int y) {
        int dx[] = {-1, 1, 0, 0};
        int dy[] = {0, 0, -1, 1};
        StringBuilder islandShape = new StringBuilder();
        int[][] queue = new int[grid.length * grid[0].length][2];
        int front = 0, rear = 0;
        queue[rear][0] = x;
        queue[rear++][1] = y;
        grid[x][y] = 0;
        while (front < rear) {
            int currentX = queue[front][0];
            int currentY = queue[front++][1];
            islandShape.append(currentX - x).append(",").append(currentY - y).append(",");
            for (int i = 0; i < 4; i++) {
                int nx = currentX + dx[i];
                int ny = currentY + dy[i];
                if (nx >= 0 && nx < grid.length && ny >= 0 && ny < grid[0].length && grid[nx][ny] == 1) {
                    queue[rear][0] = nx;
                    queue[rear++][1] = ny;
                    grid[nx][ny] = 0;
                }
            }
        }
        return islandShape.toString();
    }
}

